class Solution {
    private int count(int num,int digit){
        int cnt = 0;
        while(num>0){
            if(num%10 == digit)
                cnt++;
            num = num/10;
        }
        return cnt;
    }
    public int countDigitOccurrences(int[] nums, int digit) {
        int tot = 0;
        for(int i:nums){
            tot += count(i,digit);
        }
        return tot;
    }
}

